import React, { useState } from 'react';

export const SignupForm: React.FC = () => {
  const [email, setEmail] = useState('');
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (email) {
      setSubmitted(true);
      setEmail('');
    }
  };

  return (
    <section className="py-24 md:py-40">
      <div className="container mx-auto px-4 max-w-4xl text-center">
        <h2 className="text-4xl md:text-6xl font-bold tracking-tight mb-8">Ready to deploy?</h2>
        <p className="text-xl text-zinc-500 mb-12 max-w-xl mx-auto">Join 5,000+ developers shipping beautiful documentation every day.</p>

        <div className="max-w-md mx-auto">
          {submitted ? (
            <div className="p-6 rounded-2xl bg-emerald-500/10 border border-emerald-500/20 text-emerald-500 font-medium">
              Thanks! We've added you to the list. Keep an eye on your inbox.
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="flex flex-col sm:flex-row gap-3">
              <input
                type="email"
                required
                placeholder="developer@company.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="flex-1 bg-zinc-900 border border-zinc-800 rounded-xl px-4 py-4 text-white placeholder-zinc-600 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all"
              />
              <button
                type="submit"
                className="bg-indigo-600 hover:bg-indigo-700 text-white font-bold px-8 py-4 rounded-xl transition-all"
              >
                Join Now
              </button>
            </form>
          )}
          <p className="mt-4 text-zinc-600 text-xs">No spam. Only major updates and beta invites.</p>
        </div>
      </div>
    </section>
  );
};

