import React, { useMemo } from 'react';

interface DotProps {
  count?: number;
}

export const BackgroundDots: React.FC<DotProps> = ({ count = 150 }) => {
  // Generate random positions and properties once to avoid re-renders
  const dots = useMemo(() => {
    return Array.from({ length: count }).map((_, i) => ({
      id: i,
      top: `${Math.random() * 100}%`,
      left: `${Math.random() * 100}%`,
      size: `${Math.random() * 2 + 1}px`,
      opacity: Math.random() * 0.5 + 0.1,
      delay: `${Math.random() * 5}s`,
      duration: `${Math.random() * 3 + 2}s`,
    }));
  }, [count]);

  return (
    <div className="absolute inset-0 w-full h-full pointer-events-none">
      <style>
        {`
          @keyframes twinkle {
            0%, 100% { opacity: 0.2; transform: scale(1); }
            50% { opacity: 1; transform: scale(1.2); }
          }
          .shiny-dot {
            animation: twinkle var(--duration) ease-in-out infinite;
            animation-delay: var(--delay);
          }
        `}
      </style>
      {dots.map((dot) => (
        <div
          key={dot.id}
          className="shiny-dot absolute rounded-full bg-white shadow-[0_0_8px_rgba(255,255,255,0.8)]"
          style={{
            top: dot.top,
            left: dot.left,
            width: dot.size,
            height: dot.size,
            opacity: dot.opacity,
            '--delay': dot.delay,
            '--duration': dot.duration,
          } as React.CSSProperties}
        />
      ))}
    </div>
  );
};

