import React, { useMemo } from 'react';

interface DotProps {
  count?: number;
}

export const BackgroundDots: React.FC<DotProps> = ({ count = 250 }) => {
  const dots = useMemo(() => {
    return Array.from({ length: count }).map((_, i) => ({
      id: i,
      top: `${Math.random() * 100}%`,
      left: `${Math.random() * 100}%`,
      size: `${Math.random() * 3 + 1}px`, // Slightly larger dots
      opacity: Math.random() * 0.6 + 0.2, // More opaque baseline
      delay: `${Math.random() * 10}s`, // Longer delay range for better distribution
      duration: `${Math.random() * 4 + 3}s`,
    }));
  }, [count]);

  return (
    <div className="absolute inset-0 w-full h-full pointer-events-none">
      <style>
        {`
          @keyframes twinkle {
            0%, 100% { 
              opacity: 0.2; 
              transform: scale(1);
              filter: blur(0px);
            }
            50% { 
              opacity: 1; 
              transform: scale(1.5);
              filter: blur(0.5px);
            }
          }
          .shiny-dot {
            animation: twinkle var(--duration) ease-in-out infinite;
            animation-delay: var(--delay);
            will-change: transform, opacity;
          }
        `}
      </style>
      {dots.map((dot) => (
        <div
          key={dot.id}
          className="shiny-dot absolute rounded-full bg-indigo-200 shadow-[0_0_10px_rgba(165,180,252,0.8)]"
          style={{
            top: dot.top,
            left: dot.left,
            width: dot.size,
            height: dot.size,
            opacity: dot.opacity,
            '--delay': dot.delay,
            '--duration': dot.duration,
          } as React.CSSProperties}
        />
      ))}
    </div>
  );
};

