import { ExampleDocs } from './components/ExampleDocs';
import { Features } from './components/Features';
import { Testimonials } from './components/Testimonials';
import { Pricing } from './components/Pricing';
import { SignupForm } from './components/SignupForm';
import { Footer } from './components/Footer';
import { BackgroundDots } from './components/BackgroundDots';

const App: React.FC = () => {
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('theme');
      if (saved) return saved as 'dark' | 'light';
      return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
    }
    return 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
      root.classList.remove('light');
    } else {
      root.classList.add('light');
      root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => (prev === 'dark' ? 'light' : 'dark'));
  };

  return (
    <div className={`min-h-screen selection:bg-indigo-500/30 relative transition-colors duration-300 ${theme === 'dark' ? 'bg-[#0a0a0a]' : 'bg-white'} scroll-smooth`}>
      {/* Background Layer */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none z-0">
        <div className={`absolute top-[-10%] left-[-10%] w-[50%] h-[50%] rounded-full blur-[120px] transition-opacity duration-500 ${theme === 'dark' ? 'bg-indigo-500/10 opacity-100' : 'bg-indigo-500/5 opacity-60'}`} />
        <div className={`absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] rounded-full blur-[120px] transition-opacity duration-500 ${theme === 'dark' ? 'bg-blue-500/10 opacity-100' : 'bg-blue-500/5 opacity-60'}`} />
        <BackgroundDots count={300} theme={theme} />
      </div>

      <div className="relative z-10">
        <Navbar theme={theme} toggleTheme={toggleTheme} />
        <main>
          <Hero />
          <ExampleDocs theme={theme} />
          <HowItWorks />
          <Features />
          <Testimonials />
          <Pricing />
          <SignupForm />
        </main>
        <Footer />
      </div>
    </div>
  );
};

export default App;

