                  value={domain}
                  onChange={(e) => setDomain(e.target.value)}
                  className="flex-1 bg-zinc-100 dark:bg-black/40 border border-zinc-200 dark:border-white/10 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all"
                />
                <button type="submit" className="bg-zinc-900 dark:bg-white text-white dark:text-black px-6 py-3 rounded-xl text-sm font-bold hover:opacity-90 active:scale-95 transition-all">
