                    <div className="text-[10px] font-bold text-zinc-400 uppercase tracking-widest mb-1">CDN</div>
                    <span className="text-[10px] font-bold text-indigo-500 bg-indigo-500/10 px-2 py-0.5 rounded-full">GLOBAL</span>
                 </div>
              </div>
              <button onClick={() => setStep('idle')} className="text-xs text-zinc-500 hover:text-zinc-900 dark:hover:text-white transition-colors underline underline-offset-4">
                Connect another domain
              </button>
            </div>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {[
          { icon: '🔒', title: 'Auto SSL', desc: 'Let\'s Encrypt certificates managed automatically.' },
          { icon: '⚡', title: 'Edge Network', desc: 'Global CDN distribution for <100ms latency.' },
          { icon: '🔄', title: 'Wildcard Support', desc: 'Easily manage subdomains for versions.' }
        ].map(item => (
          <div key={item.title} className="p-6 rounded-2xl border border-zinc-100 dark:border-white/5 bg-zinc-50 dark:bg-white/5">
